+func TestMossMergeWithBatchEx(t *testing.T) {
+	s := open(t, &test.TestMergeCounter{})
+	defer cleanup(t, s)
+
+	// Test merge operations with pre-allocated buffer (NewBatchEx)
+	writer, err := s.Writer()
+	if err != nil {
+		t.Fatal(err)
+	}
+
+	// Create a batch with pre-allocated buffer
+	key1 := []byte("key1")
+	val1 := []byte("val1")
+	val2 := []byte("val2")
+
+	totalBytes := len(key1)*2 + len(val1) + len(val2)
+	_, batch, err := writer.NewBatchEx(store.KVBatchOptions{
+		NumMerges:  2,
+		TotalBytes: totalBytes,
+	})
+	if err != nil {
+		t.Fatal(err)
+	}
+
+	// Perform merge operations
+	batch.Merge(key1, val1)
+	batch.Merge(key1, val2)
+
+	// Execute the batch - this should work with the fix
+	err = writer.ExecuteBatch(batch)
+	if err != nil {
+		t.Fatalf("ExecuteBatch failed: %v", err)
+	}
+
+	err = batch.Close()
+	if err != nil {
+		t.Fatal(err)
+	}
+
+	// Verify the merge was applied
+	reader, err := s.Reader()
+	if err != nil {
+		t.Fatal(err)
+	}
+
+	val, err := reader.Get(key1)
+	if err != nil {
+		t.Fatal(err)
+	}
+	if val == nil {
+		t.Fatal("expected to find merged value")
+	}
+
+	// The TestMergeCounter merge operator concatenates values
+	expectedVal := []byte("val1val2")
+	if string(val) != string(expectedVal) {
+		t.Fatalf("expected %s, got %s", expectedVal, val)
+	}
+
+	err = reader.Close()
+	if err != nil {
+		t.Fatal(err)
+	}
+
+	err = writer.Close()
+	if err != nil {
+		t.Fatal(err)
+	}
+}
